from haystack import component
from vex_sdk import VexClient

@component
class PrivilegeGuard:
    def __init__(self):
        self.vex = VexClient(api_key="your-vex-key")

    @component.output_types(output=str, blocked=bool)
    def run(self, text: str):
        result = self.vex.check_privilege(text, context="legal")
        if result['risk_score'] > 0.7:
            return {'output': '', 'blocked': True}
        return {'output': text, 'blocked': False}

from haystack import component
from vex_sdk import VexClient

@component
class CitationVerifier:
    def __init__(self):
        self.vex = VexClient(api_key="your-vex-key")

    @component.output_types(verified=str, citations=list, valid=bool)
    def run(self, generated_text: str, retrieved_docs: list):
        result = self.vex.verify_legal_citations(
            text=generated_text,
            context_docs=retrieved_docs,
            jurisdiction="US"
        )
        return {
            'verified': generated_text if result['valid'] else '',
            'citations': result['citations'],
            'valid': result['valid']
        }
